mapper.select:
SELECT ID, PARENT_ID, STORAGE_YARD_NM, SHORT_CD, AREA, STORAGE_YARD_TYPE_CD, IS_INNER_STORAGE_YARD, UNIT_AREA_TON, IS_RENT, WORK_AREA_CD, SORT_NUM, STORAGE_YARD_LEVEL FROM M_STORAGE_YARD
AND STORAGE_YARD_LEVEL = #{storageYardLevel}
AND PARENT_ID = #{parentId}
ORDER BY STORAGE_YARD_NM

mapper.update:
UPDATE M_STORAGE_STACK_POSITION 
SET DEL_FLAG = '1'
WHERE STACK_ID = #{stackId}

mapper.select:
SELECT temp_t1.STOREHOUSE_ID, temp_t1.STOREHOUSE_NAME, temp_t1.REGION_ID, temp_t1.REGION_NAME, temp_t1.MASS_ID, temp_t1.MASS_NAME, SUM (temp_t1.TON) TON FROM ( SELECT t1.STOREHOUSE_ID, t1.STOREHOUSE_NAME, t1.REGION_ID, t1.REGION_NAME, t1.MASS_ID, t1.MASS_NAME, t1.TON FROM T_PRD_PORT_STORAGE_DETAIL t1, (SELECT STACK_ID ,DEL_FLAG,max(CREATE_TIME) CREATE_TIME FROM M_STORAGE_STACK_POSITION GROUP BY STACK_ID,DEL_FLAG) t2 WHERE T2.DEL_FLAG = 0 AND T2.STACK_ID = T1.MASS_ID AND T2.CREATE_TIME <= T1.CREATE_TIME ) temp_t1
AND temp_t1.MASS_ID = #{massId}
GROUP BY temp_t1.STOREHOUSE_ID, temp_t1.STOREHOUSE_NAME, temp_t1.REGION_ID, temp_t1.REGION_NAME, temp_t1.MASS_ID, temp_t1.MASS_NAME
